INSERT INTO `cpl` VALUES ('0d59247e-b861-4919-8138-40c36d4cd04d','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL14','Mampu melakukan evaluasi diri dan supervisi terhadap penyelesaian pekerjaan sebagai wujud tanggung jawab atas pencapaian hasil kelompok kerja',NULL,'2026-06-13 09:44:30.914','2026-06-13 09:44:30.914'),('278abfce-b6d0-4dba-92ff-4006bb6dd514','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL10','Mampu menunjukkan sikap profesionalitas, integritas, dan berjati diri islami yang dilengkapi dengan kemampuan komunikasi, kepemimpinan, bekerja sama dan bertanggung jawab atas pekerjaan di bidang keahliannya, bermasyarakat, berbangsa, dan bernegara sebagai warga negara yang bangga dan cinta tanah air berlandaskan nilai ahlus sunah waljamahah',NULL,'2026-06-13 09:44:30.906','2026-06-13 09:44:30.906'),('6271e975-ce2e-4675-abb5-81af09804320','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL08','Mampu memahami dan menerapkan konsep, metode, teknik, dan tahapan data mining serta visualisasi data dalam pengolahan data, pengorganisasian data, dan penyajian informasi yang efektif, efisien, dan estetik',NULL,'2026-06-13 09:44:30.902','2026-06-13 09:44:30.902'),('72622c7f-aace-498d-a532-9049de4da49a','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL05','Mampu memahami dan menerapkan kode etik dalam penggunaan informasi dan data pada perancangan, implementasi, dan penggunaan suatu sistem',NULL,'2026-06-13 09:44:30.896','2026-06-13 09:44:30.896'),('72f1b54d-10ce-4a8d-b60a-4aed8cea7b45','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL06','Memiliki kemampuan merencanakan, menerapkan, memelihara dan meningkatkan sistem informasi organisasi untuk mencapai tujuan dan sasaran organisasi yang strategis baik jangka pendek maupun jangka panjang.',NULL,'2026-06-13 09:44:30.898','2026-06-13 09:44:30.898'),('90403176-06aa-40c5-92b8-20709b229e6e','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL09','Mampu memahami dan menerapkan model sistem, metode dan berbagai teknik peningkatan bisnis proses, peluang inovasi digital dalam pengelolaan bisnis bidang kesehatan yang memanfaatkan teknologi',NULL,'2026-06-13 09:44:30.904','2026-06-13 09:44:30.904'),('a9560b1b-6554-4b9c-bdb0-99e7a85be676','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL04','Mampu membuat perencanaan infrastruktur TI, arsitektur jaringan, layanan fisik dan cloud, menganalisa konsep identifikasi, otentikasi, otorisasi akses dalam konteks melindungi orang dan perangkat',NULL,'2026-06-13 09:44:30.894','2026-06-13 09:44:30.894'),('ada956cd-5190-4dae-84ad-f5ff95ef927e','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL11','Mampu menunjukkan sikap taat hukum, disiplin, dan menghargai keanekaragaman melalui internalisasi nilai, norma, etika akademik, semangat kemandirian, kejuangan, dan kewirausahaan',NULL,'2026-06-13 09:44:30.909','2026-06-13 09:44:30.909'),('c67a381b-bfbf-405d-b9c2-f11eb2ac6796','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL12','Mampu menunjukkan kinerja mandiri, bermutu, terukur, berfikir logis, kritis, sistematis, dan inovatif, komunikatif dalam mengembangkan ilmu pengetahuan yang memperhatikan nilai humaniora sesuai bidang keahliannya',NULL,'2026-06-13 09:44:30.911','2026-06-13 09:44:30.911'),('c6ee7449-ed14-4a1b-b9cd-e7516f28be2e','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL13','Mampu mengkaji implikasi pengembangan ilmu pengetahuan dengan menerapkan keahliannya dalam rangka menghasilkan solusi, menyusun deskripsi saintifik hasil kajian dalam bentuk laporan ilmiah yang sahih dan original dan memelihara serta mengembangan jaringan kerja dengan pembimbing, kolega, sejawat baik di dalam maupun di luar lembaga',NULL,'2026-06-13 09:44:30.913','2026-06-13 09:44:30.913'),('dea95b28-a11e-4066-8055-688fa5436273','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL01','Mampu memahami, menganalisis, dan menilai konsep dasar dan peran sistem informasi dalam mengelola data dan memberikan rekomendasi pengambilan keputusan pada proses dan sistem organisasi.',NULL,'2026-06-13 09:44:30.886','2026-06-13 09:44:30.886'),('eacdfbac-af19-42fa-bfca-b8694b831985','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL07','Mampu memahami, mengidentifikasi dan menerapkan konsep, teknik dan metodologi manajemen proyek sistem informasi.',NULL,'2026-06-13 09:44:30.900','2026-06-13 09:44:30.900'),('f34dd582-7468-4f8b-bdf2-d5d87e66bfde','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL02','Mampu merancang dan menggunakan database, serta mengolah dan menganalisa data dengan alat dan teknik pengolahan data',NULL,'2026-06-13 09:44:30.888','2026-06-13 09:44:30.888'),('fb3d15ee-98ff-42df-91a3-72d2889334f5','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL03','Mampu memahami dan menggunakan berbagai metodologi pengembangan sistem beserta alat pemodelan sistem dan menganalisa kebutuhan pengguna dalam membangun sistem informasi untuk mencapai tujuan organisasi',NULL,'2026-06-13 09:44:30.891','2026-06-13 09:44:30.891');
