CREATE TABLE `matakuliah` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `kurikulumId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `kode` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `nama` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `sks` int NOT NULL DEFAULT '3',
  `semester` int NOT NULL DEFAULT '1',
  `tipe` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'WAJIB',
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `MataKuliah_kurikulumId_fkey` (`kurikulumId`),
  CONSTRAINT `MataKuliah_kurikulumId_fkey` FOREIGN KEY (`kurikulumId`) REFERENCES `kurikulum` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
