INSERT INTO `profillulusan` VALUES ('21f0a195-9475-4733-8507-5b6c1320fb28','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','PL4','Lulusan memiliki sikap religius, beretika, dan peka terhadap lingkungan sosial sebagai seorang warga negara dengan berlandaskan nilai ahlussunah waljamaah (Aswaja).','PL Sikap','2026-06-13 09:44:30.883','2026-06-13 09:44:30.883'),('29cf8ffb-ae5d-4d5e-8cce-b00c6a96a56c','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','PL2','Lulusan memiliki kemampuan memahami, menerapkan, dan mengintegrasikan model bisnis dengan menggunakan metode dan berbagai teknik peningkatan bisnis proses yang mendatangkan suatu nilai tambah bagi organisasi (peta okupasi dalam KKNI Bidang TIK dan IS2020)','PL Penciri Utama','2026-06-13 09:44:30.879','2026-06-13 09:44:30.879'),('2eb1d20f-12c1-4ac6-acc5-c8c26122aafd','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','PL1','Lulusan memiliki kemampuan untuk merencanakan, menganalisis, merancang, membangun, mengujicoba, menerapkan, dan mengevaluasi sistem informasi (bidang x) dalam sebuah proyek yang selaras dengan tujuan organisasi (peta okupasi dalam KKNI Bidang TIK dan IS2020)','PL Penciri Utama - Pengembangan Sistem dan Teknologi Informasi, Pengembangan Perangkat Lunak dan Pemrograman, Manajemen Proyek TI','2026-06-13 09:44:30.875','2026-06-13 09:44:30.875'),('71019d9b-f925-4205-8124-005fcaf101c7','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','PL5','Lulusan memiliki kemampuan berpikir kritis dan inovatif, bekerja mandiri, membuat keputusan tepat, mendokumentasikan data dengan benar, menyusun karya ilmiah, berkomunikasi efektif, membangun jaringan kerja, bertanggung jawab atas hasil tim, dan mengelola pembelajaran secara mandiri sesuai bidang keahliannya','PL Keterampilan umum dan sikap','2026-06-13 09:44:30.885','2026-06-13 09:44:30.885'),('7480d044-e1d6-4506-9f20-29bd4c8313d4','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','PL3','Lulusan memiliki kemampuan untuk mengolah, menganalisis, dan menyajikan data yang dikembangkan dengan konsep big data dan business intelligence untuk membantu dalam proses pengambilan keputusan (peta okupasi dalam KKNI Bidang TIK)','PL tambahan KK dan P','2026-06-13 09:44:30.881','2026-06-13 09:44:30.881');
